package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"

	"github.com/gorilla/mux"
)

type Comment struct {
	ID       string `json:"id"`
	Text     string `json:"text"`
	Username string `json:"username"`
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	id := vars["id"]

	comments := []Comment{
		{ID: "1", Text: "This is a comment from user 1.", Username: "user1"},
		{ID: "2", Text: "This is a <b>bold</b> comment from user 2.", Username: "user2"},
	}

	template := `
	<html>
	<head>
		<title>Comments for {{.ID}}</title>
	</head>
	<body>
		<h1>Comments for {{.ID}}</h1>
		<ul>
			{{range .Comments}}
				<li>{{.Username}}: <i>{{.Text}}</i></li>
			{{end}}
		</ul>
	</body>
	</html>
`

	err := renderTemplate(w, template, map[string]interface{}{
		"ID":     id,
		"Comments": comments,
	})
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
}

func renderTemplate(w http.ResponseWriter, template string, data interface{}) error {
	t := htmlTemplate.Funcs(map[string]interface{}{
		"markdown": func(text string) string {
			return text
		},
	})
	err := t.Execute(w, data)
	if err != nil {
		log.Println(err)
		return err
	}
	return nil
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/comments/{id}", commentsHandler).Methods("GET")

	http.ListenAndServe(":8080", r)
}